اما آیاتی که در آنها ابتلا به معنای آزمون است؛ این سخن خداوند: خدا می‌خواهد شما را در آنچه به شما بخشیده بیازماید (

مائده/۴۸

) و این سخن خداوند: سپس خداوند شما را از آنان منصرف ساخت [و پیروزی شما به شکست انجامی] تا شما را آزمایش کند (آل عمران/۱۵۲) و نیز این سخن خداوند متعال: ما آنها را آزمودیم، همان گونه که «صاحبان باغ» را آزمایش کردیم (

قلم/۱۷

) و این سخن خدای متعال: خَلَقَ الْمَوْتَ وَ الْحَیاةَ لِیَبْلُوَکُمْ أَیُّکُمْ أَحْسَنُ عَمَلاً.

حبیب سجستانی گوید: شنیدم امام باقر (علیه السلام) می‌فرمود: چون خدا عزّوجلّ نژاد آدمیزاده را از پشتش در آورد تا از آن‌ها پیمان بر ربوبیّت ستاند برای خود، و بر نبوّت هر پیغمبر نخست پیمان بر نبوّت محمّدبن‌عبداللَّه (صلی الله علیه و آله) گرفت، وانگه فرمود: «به آدم بنگر تا چه بینی»؟ فرمود: «آدم نگریست به نژادش که ذره بودند و آسمان را انباشته بودند». و گفت: «پروردگارا چه بسیارند نژادم برای کاری بزرگ آن‌ها را آفریدی چه خواهی از آنان در گرفتن پیمان؟ خدای عزّوجلّ فرمود: آن چنان‌که تنها مرا می‌پرستند و چیزی را شریک من نخواهند ساخت. (

نور/۵۵

) باور دارند رسولانم را و پیرو آن‌ها باشند. آدم (علیه السلام) گفت: «پروردگارا، چیست مرا که بینم برخی بزرگ‌تر از دیگریند و برخی نور بیش دارند و برخی کم و برخی هیچ؟ خدا عزّوجلّ فرمود: چنین آفریدمشان تا بیازمایم آن‌ها را در هرحال. آدم گفت: پروردگارا اجازه می‌دهی در سخن تا سخنی گویم؟ فرمودش بگو که جانت از من است و طبعت جز بود من، آدم (علیه السلام) گفت: کاش همه را مانند آفریده بودی در یک اندازه و یک منش و یک غریزه، و یک رنگ، یک اندازه عمر و روزی برابر تا بهم ستم نکردند و حسد و کینه نورزیدند و در چیزی اختلاف نکردند. خدا عزّوجلّ فرمود: ای آدم به جانی که از من داری گویا شدی و به طبع سست خود سخن گفتی بدان چه ندانی، منم آفریننده‌ی دانا، به دانشم میان آفریدگانم اختلاف انداختم و به خواست، من فرمانم در آن‌ها اجراء شود. و به تدبیر و تقدیر من روانه باشند، آفرینش من دگرگون نگردد. و همانا پری و آدمی را آفریدم تا مرا پرستند و بهشت را آفریدم برای هرکه مرا پرستد و مرا فرمان برد و پیرو رسولانم گردد و باکی ندارم و دوزخ را آفریدم برای هرکه به من کافر شود و گناه کند و پیرو رسولانم نشود و باکی ندارم، و آفریدم تو را و نژادت را و بی‌نیازم به تو و آنان و همانا تو را و آنان را آفریدم تا بیازمایمت و بیازمایمشان تا کدام خوش کردارترند در دار دنیا در زندگی شماها و پیش از مرگتان و ازاین‌رو دنیا و آخرت آفریدم و زندگی و مرگ و طاعت و معصیت و بهشت و دوزخ. در تقدیر و تدبیرم چنین خواستم، و به دانشم که در آنان نافذ است، صورت و تن و رنگ و عمر و روزی و طاعت و گناه آنان را چندگونه ساختم و از آن‌ها خوشبخت و بدبخت و بینا و کور و کوتاه و بلند و زیبا و زشت و دانا و نادان و توانگر و درویش و فرمانبر و نافرمان و تندرست و بیمار و زمین‌گیر و بی‌آفت ساختم. پس تندرست به آفت زده بنگرد و بر عافیت خود مرا سپاس گوید و آفت زده بدو بنگرد و از من عافیت خواهد به بلایم صبر کند و عطای شایانش بدهم و توانگر به درویش نگرد و مرا سپاس و شکر گوید و درویش به توانگر نگرد و به درگاهم دعا کند و خواهش کند، و مؤمن به کافر نگرد و مرا به رهنمونیش سپاس گوید. برای این چنانشان آفریدم که در خوشی و ناخوشی آن‌ها را بیازمایم و در عافیت بخشی و بلادادن و در آنچه بدان‌ها بدهم و یا دریغ کنم، منم خدای مالک توانا و مرا رسد که آنچه مقدّر کردم طبق تدبیرم اجراء نمایم و مرا رسد که دیگرگون سازم از آن هرجور خواهم و پیش اندازم آنچه پس انداختم و پس اندازم آنچه پیش داشتم، منم خدا که هر کار خواهم کنم و از هرچه کنم بازپرسی ندارد و بازپرسی کنم از هرچه خلقم کنند.

در نامه‌ای به مردم اهواز هنگامی‌که درباره‌ی جبر و اختیار از ایشان پرسیدند؛ فرمود: ... تمامی مردم به‌طور کلّی در این اتّفاق نظر دارند و اختلافی در بین آنان وجود ندارد، که قرآن حق است و تمامی فرقه‌ها در آن شک و تردیدی ندارند. پس اگر آن‌ها بر آن (قرآن) اجماع کنند، مُصیب و بر حق هستند و با تصدیق‌کردن آنچه خداوند نازل کرده، به گفتار پیامبر (صلی الله علیه و آله) هدایت داده می‌شوند که فرمود: «امّت من بر گمراهی اجماع نخواهند داشت. پس حضرت خبر داد که آنچه امّت نسبت به آن نظر اجماع خواهند داشت و با همدیگر نسبت به آن خلافی نداشته باشند، همان حق است، و این معنا و مفهوم حدیث است، نه آن چیزی که جاهلان تأویل می‌کنند و نه آن چیزی که مخالفان می‌گویند که دستورات قرآن را باطل می‌کنند و از دستورات احادیث تحریف شده و روایت‌های پرزرق و برق، و از هواهای نفسانی نابودکننده که با سخن صریح قرآن و معنای آیات واضح و روشن آن مغایرت دارد، پیروی می‌کنند. ما از خداوند می‌خواهیم که توفیق راه درست را عنایت فرماید و ما را به راه راست هدایت کند. سپس فرمود: اگر قرآن نسبت به تأیید خبری گواهی داد و آن را محقّق شمرد و گروهی از مردم آن را انکار کنند و با یکی از این حدیث‌های پرزرق و برق با آن مخالفت کنند، به‌واسطه‌ی همین انکار و مخالفت با قرآن، به کافر و گمراه تبدیل میشوند. صحیح‌ترین و درست‌ترین خبری که از جانب قرآن محقّق و مسلّم شمرده شده است، از قبیل خبری است که از رسول خدا (صلی الله علیه و آله) نقل شده است و همگان بر آن اتّفاق نظر دارند که می‌فرماید: من قرآن و عترت خویش را نزد شما باقی می‌گذارم، به محض این که به آن‌ها چنگ زدید و یا پایبند بودید به هیچ وجه بعد از من گمراه نخواهید شد، و این دو از هم جدا نخواهند شد تا اینکه در حوض کوثر بر من وارد شوند، و سخن دیگر ایشان با همین مضمون؛ من دو چیز گرانبها را نزد شما به امانت می‌گذارم، قرآن و عترتم، اهل بیت من، و این دو از هم جدا نخواهند شد تا اینکه در حوض کوثر بر من وارد شوند، و به محض آنکه به آن‌ها پایبند شوید و چنگ بزنید، گمراه نخواهید شد. هنگامی‌که شواهد این حدیث را به‌طور صریح در قرآن می‌بینیم: ولیّ شما تنها خدا و پیامبر اوست و کسانی که ایمان آورده‌اند؛ همان کسانی که نماز برپا می‌دارند و درحال رکوع زکات می‌دهند. (

مائده/۵۵

) و همه‌ی روایت‌های علماء بر این اتّفاق نظر دارد که در خصوص امیرالمؤمنین (علیه السلام) است که درحال رکوع انگشتر خویش را بخشید و خداوند از این کار وی قدردانی کرد، و آیه را در شأن ایشان نازل کرد و رسول خدا (صلی الله علیه و آله) را می‌بینیم که وی را از سایر یارانش جدا نمود و ممتاز ساخت و فرمود: «هرکس من مولای اویم، علی (علیه السلام) مولای اوست، خداوندا! دوستداران وی را دوست بدار، و دشمنانش را دشمن بدار». نیز سخن ایشان (صلی الله علیه و آله) که می‌فرماید: «علی (علیه السلام) دین و بدهی مرا اداء می‌کند و عهد و پیمان مرا انجام می‌دهد و او جانشین و خلیفه‌ی شما بعد از من است». و نیز این سخن ایشان (صلی الله علیه و آله) هنگامی‌که وی را جانشین خویش در مدینه کرد و علی (علیه السلام) عرض کرد: «ای رسول خدا (صلی الله علیه و آله)! آیا مرا بر زنان و کودکان میگماری تا در این زمینه جانشین شما باشم «؟! فرمود: «مگر ملاحظه نمی‌کنی که نسبت تو به من مانند نسبت هارون به موسی (علیه السلام) است، جز اینکه بعد از من پیامبری نیست؟! پس دانستیم که قرآن بر صحّت‌داشتن این اخ-بار و محقّق داشت-ن این گواه‌ها شه-ادت داد. پس بر امّت است، اگر این اخبار با قرآن موافق بود و قرآن با این اخبار موافق بود، به آن اعتراف کند؛ بنابراین هنگامی‌که آن را با قرآن هماهنگ یافتیم، و قرآن را با این اخبار موافق یافتیم و گواهی بر آن بود، اقتدا و پیروی از این اخبار واجب است و به جز ستیزه‌جویان و مفسدان از این حدّ الهی تجاوز نخواهند کرد». سپس فرمود: «منظور و مقصود ما سخن‌گفتن در باب جبر و اختیار و شرح‌دادن و بیان نمودن این دو است، و هدف از آنچه گفته شد عبارت است از هماهنگی و هم خوانی قرآن و خبر؛ اگر با یکدیگر موافق باشند، دلیل و گواهی است بر آنچه که درپی آن هستیم و تأییدی باشد بر آنچه ما به‌دنبال بیان آن هستیم ان‌شاءالله تعالی». پس فرمود: «هنگامی‌که از امام جعفر صادق (علیه السلام) در خصوص جبر و اختیار پرسیده شد، فرمود: نه جبری وجود دارد و نه اختیار، بلکه چیزی بین این دو امر است». گفته شد: «ای فرزند رسول خدا (صلی الله علیه و آله)! منظور چیست»؟ فرمود: «سالم‌بودن عقل، مهیّاکردن راه، و مهلت در زمان، و توشه قبل از سفر، و انگیزه‌ی فاعل از عمل خویش، و این پنج چیز است که اگر بنده در یکی از آن‌ها کمبودی داشته باشد، عمل از جانب وی متروک خواهد بود، و من برای هریک از این سه باب که همانا، جبر و اختیار و حدّ فاصل بین دو امر است، مثالی می‌آورم که معنی و مفهوم را برای طالب آن نزدیک نماید و شرح‌کردن بحث را بر وی آسان گرداند و قرآن با آیات متین و استوارش بر آن گواهی دهد و تأییدکردن آن از سوی خردمندان محقّق شود. در امان ماندن از گناه و به دست‌آوردن توفیق در دست خداوند است». سپس فرمود: «امّا در خصوص جبر، هرکس گمان کند و چنین حرفی را بزند که خداوند عزّوجلّ، بندگان را بر گناهان مجبور کرده است و آنان را به خاطر آن گناهان مجازات می‌کند، به خداوند ظلم کرده است و این سخن او را که می‌فرماید: و پروردگارت به هیچ‌کس ستم نمی‌کند. (

کهف/۴۹

) و هم‌چنین این سخن او را که می‌فرماید: [و به آنان می‌گوییم]: این در برابر چیزی است که دست‌هایتان از پیش برای شما فرستاده و خداوند هرگز به بندگان ظلم نمی‌کند!. (

حج/۱۰

) و آیات زیاد دیگر دراین زمینه، را ردّ و تکذیب کرده است. هرکس گمان کند که نسبت به انجام‌دادن گناهان مجبور است، خداوند را عهده‌دار گناهان خویش دانسته و در امر مجازات به او ظلم کرده است، و هرکس به خدای خویش ظلم کند، قرآن را تکذیب کرده است، و هرکس قرآن را تکذیب کند، بنا به اتّفاق‌نظر امّت، کافر شده است. مثالی که دراین‌خصوص آورده می‌شود، این است که مردی، بنده‌ای مملوک بی‌پول را خریداری کرد که آن بنده هیچ بهره و نصیبی از دنیا و مادیّات آن نبرده بود و صاحب وی کاملاً از این مسئله آگاهی داشت. پس به وی دستور داد که به بازار رود و کالایی را از آنجا برایش بیاورد و بهای آن کالا را به وی نداد، و مولای بنده می‌دانست که صاحب آن کالا مردی است که هیچ‌کس نمی‌تواند آن کالا را از وی بخرد بدون آنکه بهای دلخواه او را پرداخت کند. مولای این بنده که خود را به عدالت و انصاف و حکمت و ستم ستیزی معرفی کرده است، بنده‌ی خویش را تهدید کرد که اگر کالا را نیاورد، وی را مجازات خواهد کرد. پس هنگامی‌که بنده راهی بازار شد و خواست که کالای مولای خود را بخرد، بر آن مانعی یافت که فقط درصورت دارابودن بهای آن می‌توانست آن را با خود ببرد و آن بنده بهای آن را نداشت؛ بنابراین ناامید از برآوردن حاجت، نزد مولای خویش بازگشت. مولایش عصبانی شد و وی را مجازات کرد؛ بنابراین او ظالمی تجاوزگر است و بر توصیفات خود مبنی بر عدالت و انصاف و حکمت، خط بطلان کشیده است و اگر بنده را مجازات نمی‌کرد، خود را تکذیب کرده است، مگر چنین نبود که نباید او را مجازات می‌کرد؟ و دروغ‌گفتن و ظلم، عدالت و حکمت را باطل می‌کنند، خداوند از آن چه جبرگرایان می‌گویند، منزّه است. سپس امام (علیه السلام) بعد از سخنانی طولانی فرمود: امّا اختیار که امام صادق (علیه السلام) آن را باطل نمود و کسی که به آن اعتقاد دارد را در اشتباه دانست، این است که کسی بگوید: خداوند تعالی، اختیار امرونهی خویش را به بندگان سپرده است و آنان را فرو گذاشته است. این سخن دقیق و عمیقی است که به‌جز ائمه هدی (علیهم السلام) از خاندان رسول خدا (صلی الله علیه و آله)، کسی به کنه و عمق آن پی نبرده است. ایشان فرمود: «اگر خداوند از روی سهل‌انگاری، به آنان اختیار داده باشد، حتماً آنچه را اختیار کرده بودند، رضایت‌مندی وی را درپی دارد و سزاوار ثواب و پاداش می‌شوند و نسبت به گناهانی که مرتکب شدند، مجازاتی نخواهند داشت. اگر این اهمال و سهل‌انگاری صحّت داشته باشد، این گفتار بر دو نوع خواهد بود: یا اینکه بندگان علیه او همدستی کردند و او را به قبول‌کردن اختیارداشتن آن‌ها در آراء خویش مجبور کردند که دراین‌صورت، چه بخواهد و چه نخواهد، سستی و ضعف به او راه خواهد یافت، یا اینکه خداوند عزّوجلّ از به بندگی در آوردن آنان با امرونهی و از روی اراده و خواست خود عاجز بود، پس امرونهی خویش را به آنان سپرد و امرونهی خود را برطبق خواسته آنان قرار داد. از آنجا که از به بندگی درآوردن آنان با امرونهی و از روی اراده خود عاجز شد، بنابراین در خصوص کفر و ایمان به آن‌ها اختیار داد. این موضوع مانند مردی است که بنده‌ای را خریداری کرده تا به وی خدمت کند و حقّ سروری وی را به‌جای آورد و امرونهی وی را انجام دهد و مالک آن بنده ادّعا میکند که او توانا، شکست‌ناپذیر، عزیز و داناست. پس به بنده‌ی خویش دستور می‌دهد و امرونهی میکند و به وی وعده میدهد که اگر از دستورات خویش پیروی کند، پاداشی عظیم به وی خواهد داد، و اگر از دستورات وی سرپیچی کند، به شدیدترین شکل مجازات خواهد شد. امّا بنده از خواسته‌های مالک خویش سرباز میزند و از دستورات او سرپیچی میکند و هر دستوری که به وی می‌دهد، به آن عمل نمی‌کند و به خواسته‌های مالک خویش اهمیّتی نمی‌دهد، بلکه از خواسته و اراده‌ی خویش پیروی می‌کند. سپس بنده‌ی خویش را برای برآوردن نیازهای خویش میفرستد، و بنده از خواسته خویش پیروی میکند و چیزهایی برخلاف آنچه مالک وی به آن نیاز داشته با خود میآورد. پس هنگامی‌که نزد مولای خویش بازمیگردد، مولا به آنچه بنده خویش آورده بود، نگاه کرده و ملاحظه میکند که برخلاف آن چیزی است که به وی دستور داده بود. پس بنده میگوید: من با توجّه به اینکه کار را به من سپردی، عمل کردم و از اراده و خواست خودم پیروی کردم و کسی که کاری به وی سپرده می‌شود [اختیار تامّ دارد]، از چیزی منع نمی‌شود، به این دلیل که اختیار و ممانعت در یکجا جمع نمی‌شوند. سپس فرمود: و هرکس ادّعا کند که خداوند، قبول امرونهی خود را به بندگان خویش سپرده است، قائل به عجز و ناتوانی خداوند شده است و بر وی واجب دانسته که همه‌ی اعمال خیر و شرّ آنان را بپذیرد، و امرونهی خداوند را باطل و نفی کرده است. سپس فرمود: خداوند، خلق را با قدرت خویش آفرید و توانایی به بندگی درآوردن آنان با اس-تفاده از امرونهی را در وجود آن‌ها قرار داده اس-ت و اطاعت ایش-ان از امرونهی خوی-ش را از آنان پذیرفت و از این پذیرش آنان راضی بوده و آنان را از عصیان و سرکشی خویش بازداشت. هرکسی را که معصیت و نافرمانی او کند، مورد مذمت قرار داده و به وی وعده مجازات داده است. حقّ اختیار امرونهی در دست خداوند است، آنچه را می‌خواهد، برمی‌گزیند و به آن امر میکند، و از آنچه برای او ناپسند آید، نهی می‌کند و با استفاده از قدرتی که در وجود بندگانش قرار داده و آنان را قادر به پیروی از امر او و یا اجتناب از گناهانش کرده است، مجازات میکند و یا اینکه به آنان پاداش میدهد؛ زیرا او عدل است، و عدالت و انصاف از اوست و حجّت را با هشداردادن و تهدیدکردن، تمام کرده است و گزینش از آن اوست، و هر آن کس را که او بخواهد اختیار می‌کند، و محمّد (صلی الله علیه و آله) را انتخاب و گزینش نمود و با رسالت خویش، وی را بر خلق خویش مبعوث کرد و اگر اختیار امورش را به بندگانش سپرده بود، به قریش این اجازه را می‌داد که امیهًْ‌بن‌ابی صلت و مسعود ثقفی را انتخاب کنند، و این دو نزد آنان از محمّد (صلی الله علیه و آله) والاتر بودند، و گفتند: چرا این قرآن بر مرد بزرگ [و ثروتمندی] از این دو شهر (مکّه و طائف) ناز ل نشده است؟!. (

زخرف/۳۱

) و منظورشان همان دو مرد بود، و این همان چیزی است که بین دو امر است، نه جبر و نه اختیار است، و این همان چیزی که امیرالمؤمنین (علیه السلام) در پاسخ به سؤال عبایهًْ‌بن‌ربعی اسدی در خصوص استطاعت و توانایی فرمود. آن حضرت فرمود: «بدون خداوند، صاحب آن هستی، یا همراه خداوند»؟ عبایهًْ‌بن‌ربعی ساکت شد. پس فرمود: «ای عبایه! بگو». عرض کرد: «چه بگویم، ای امیرالمؤمنین (علیه السلام)»؟ فرمود: «اگر بگویی که به همراه خداوند، صاحب آن هستی، تو را به قتل خواهم رساند، و اگر بگویی که بدون خداوند، صاحب آن هستی، تو را نیز به قتل خواهم رساند». عرض کرد: «پس چه بگویم، ای امیرالمؤمنین (علیه السلام)»؟ فرمود: «بگو، از طریق خداوند که مالک و صاحب اصلی آن است، صاحب آن هستی که اگر تو را صاحب اختیار آن کند، از بخشش وی است و اگر آن را از تو بگیرد، این از باب امتحان و بلای وی است، و اوست مالک آنچه تو را صاحب اختیار آن کرده و تو را بر آن توانا ساخته است. مگر نمی‌بینی که مردم «حَول و قوّت» را می‌طلبند، هنگامی‌که می‌گویند: لاَ حَولَ وَ لاَ قُوّةَ إلاَّ بِاللهِ»؟ آن مرد عرض کرد: «ای امیرالمؤمنین (علیه السلام)! تأویل این آیه چیست»؟ فرمود: «قدرتی در برابر گناهان و معصیت‌های خداوند نداریم، مگر پایبندی به عصمت خداوند، و قوّت و نیرویی برای اطاعت از خداوند نداریم، مگر آنکه خداوند به ما یاری کند». گفت: «آن مرد از جای خود پرید و دست و پای وی را بوسید. سپس در خصوص سخن خداوند: ما همه‌ی شما را قطعاً می‌آزماییم تا معلوم شود مجاهدان واقعی و صابران از میان شما کیانند، و اخبار شما را بیازماییم!. (محمّد/۳۱) و آیه‌ی به تدریج از جایی که نمی‌دانند، گرفتار مجازاتشان خواهیم کرد. (

اعراف/۱۸۲

) و آیه: بگویند: «ایمان آوردیم»، به حال خود رها می‌شوند و آزمایش نخواهند شد؟!. (

عنکبوت/۲

) و آیه: ما سلیمان را آزمودیم. (

ص/۳۴

) و آیه: ما قوم تو را بعد از تو، آزمودیم و سامری آن‌ها را گمراه ساخت!. (

طه/۸۵

) و سخن موسی (علیه السلام) که می‌فرماید: این، جز آزمایش تو، چیز دیگر نیست. (

اعراف/۱۵۵

) و آیه: ولی خدا می‌خواهد شما را در آنچه به شما بخشیده بیازماید. (

مائده/۴۸

) و آیه: سپس خداوند شما را از آنان منصرف ساخت [و پیروزی شما به شکست انجامید] تا شما را آزمایش کند. (آل عمران/۱۵۲) و آیه: ما آن‌ها را آزمودیم، ه-مان‌گونه که «صاحبان باغ» را آزمایش کردیم. (

قلم/۱۷

) و آیه: لِیَبْلُوَکُمْ أَیُّکُمْ أَحْسَنُ عَمَلًا و آیه: [به خاطر آورید] هنگامی‌که خداوند، ابراهیم را با وسایل گوناگونی آزمود. (

بقره/۱۲۴

) و آیه: و اگر خدا می‌خواست خودش آن‌ها را مجازات می‌کرد، امّا می‌خواهد بعضی از شما را با بعضی دیگر بیازماید. (محمّد/۴)» فرمود: «تمامی این آیات در قرآن در معنای امتحان و آزمایش آمده است، سپس فرمود: اگر بگویند: حجّت و دلیل در سخن خداوند عزّوجلّ چیست، که می‌فرماید: هرکس را بخواهد گمراه می‌سازد و هرکس را بخواهد هدایت می‌کند. (

فاطر/۸

) و این به چیزی شباهت دارد»؟ می‌گوییم: فهمیدن معنای مجازی این آیه، درک‌کردن دو معنا و مفهوم را می‌طلبد: اوّل اینکه آگاهی‌دادن نسبت به آنکه خداوند تعالی قادر است که هر آن کس را که بخواهد، هدایت کند و هر آن‌کس را که بخواهد، گمراه کند، و اگر آنان را بر یکی از دو مسیر مجبور می‌کرد، آن گونه که شرح دادیم، پاداش و مجازات را بر آن‌ها واجب نمی‌دانست. دوّم اینکه؛ یکی از معانی هدایت، معرفی‌کردن و شناساندن است، آن‌گونه که خداوند تعالی می‌فرماید: امّا ثمود را هدایت کردیم، ولی آن‌ها نابینایی را بر هدایت ترجیح دادند. (

فصلت/۱۷

) و این‌طور نیست که هر آیه متشابهی در قرآن، حجّتی باشد بر حکم آیاتی که دستور داده شد که به آن چنگ زنیم و از آن‌ها پیروی کنیم. و این همان سخن خداوند است که می‌فرماید: او کسی است که این کتاب [آسمانی] را بر تو نازل کرد، که قسمتی از آن، آیات «محکم» [صریح و روشن] است که اساس این کتاب می‌باشد [و هرگونه پیچیدگی در آیات دیگر، با مراجعه به این‌ها، برطرف می‌گردد]. و قسمتی از آن، «متشابه» است [آیاتی که به خاطر بالابودن سطح مطلب و جهات دیگر، در نگاه اوّل، احتمالات مختلفی در آن می‌رود ولی با توجّه به آیات محکم، تفسیر آن‌ها آشکار می‌گردد]. امّا آن‌ها که در قلوبشان انحراف است، به‌دنبال متشابهاتند، تا فتنه‌انگیزی کنند [و مردم را گمراه سازند] و تفسیر [نادرستی] برای آن می‌طلبند. (آل عمران/۷) و می‌فرماید: پس بندگان مرا بشارت ده! همان کسانی که سخنان را می‌شنوند و از نیکوترین آن‌ها پیروی می‌کنند آنان کسانی هستند که خدا هدایتشان کرده، و آن‌ها خردمندانند. (

زمر/۱۸-۱۷

) خداوند ما و شما را به آنچه می‌خواهد و می‌پسندد توفیق دهد و ما و شما را با کرامت و مقام و منزلت آشنا سازد و هدایت کند و ما و شما را به آنچه برای ما و شما خیر است و ماندگارتر است، هدایت کند. همانا وی آنچه را می‌خواهد انجام می‌دهد. او حکیم و جواد و مجید است.

اصبغ‌بن‌نباته نقل کرده است: مردی از علی (علیه السلام) درباره‌ی شب قدر پرسید ... و گفت: «می‌بینم که شب قدر را چنین یاد می‌کنی: فرشتگان و «روح» در آن شب می‌شوند. (

قدر/۴-۳

)»؟ علی (علیه السلام) به او فرمود: «اگر شرح آن بر تو معلوم نشد، [توضیح] آشکاری از آن در اختیار تو قرار می‌دهم که داناترین مردم سرزمینت به‌معنای شب قدر باشی». آن مرد گفت: «دراین‌صورت لطف [بزرگی] به من کرده‌ای». علی (علیه السلام) به او فرمود: «خداوند تنهاست و تک‌بودن را دوست دارد و تنها است و تک‌بودن را برگزید و همه چیز را بر هفت تا بودن جاری ساخت؛ هفت آسمان را آفرید، و از زمین نیز همانند آن‌ها را. و فرمود: خَلَقَ سَبْعَ سَماواتٍ طِباقاً. [پس شب قدر را میان هفت شب آخر جستجو کن].

حسین‌بن‌خالد گوید: از امام رضا (علیه السلام) درباره‌ی آیه: قسم به آسمان که دارای چین و شکن‌های زیباست. (

ذاریات/۷

) پرسیدم. فرمود: «آسمان‌ها وابسته به زمینند و انگشتان خود را درهم کرد». گفتم: «چگونه وابسته به زمینند با اینکه خدا می‌فرماید: آسمان‌ها را، بدون ستون‌هایی که برای شما دیدنی باشد، برافراشت. (

رعد/۲

) فرمود: «سبحان اللَّه آیا نمی‌فرماید بِغَیْرِ عَمَدٍ تَرَوْنَها»؟ گفتم: «چرا»؟ فرمود: «پس ستونی هست ولی دیده نشود». گفتم: «فدایت شوم! این چگونه می‌باشد». کف چپ خود را گشود و کف راستش را بر آن نهاد. و فرمود: «این زمین دنیا است که آسمان دنیا بالایش گنبد است، و زمین دوّم بالای آسمان دنیا است و آسمان دوّم بالایش گنبد است و زمین سوّم بالای آسمان دوّم است و آسمان سوّم بالایش گنبد است، و زمین چهارم بالای آسمان سوّم است و آسمان چهارم بالایش گنبد است، و زمین پنجم بالای آسمان چهارم است و آسمان پنجم بالایش گنبد است، و زمین ششم بالای آسمان پنجم است و آسمان ششم بالایش گنبد است، و زمین هفتم بالای آسمان ششم است و آسمان هفتم بالایش گنبد است و عرش رحمان تبارک‌وتعالی بالای آسمان هفتم است. و این است سخن خداوند عزّوجلّ: هفت آسمان را آفرید، و از زمین نیز همانند آن‌ها را فرمان او در میان آن‌ها پیوسته فرود می‌آید. (

طلاق/۱۲

) و امّا صاحب الأمر رسول خدا (صلی الله علیه و آله) است و وصیّ پس از او که بر روی زمین بر پاست، و همانا فرمان از بالای آسمان‌ها و زمین‌ها به او فرود می‌آید. گفتم: «زیر پای ما جز یک زمین نیست»؟ فرمود: «زیر پای ما جز یک زمین نیست و به‌راستی که شش زمین دیگر بالای سر ما هستند».

سلیمان‌بن‌جعفر از امام کاظم (علیه السلام) از پدرانش نقل کرده است: دعا برای [حفظ] حیوان [از چشم زخم]: و آن [دعا] نزد ائمّه (علیهم السلام) محفوظ است؛ که فرمود: به‌نام خداوند بخشنده‌ی مهربان؛ به‌نام خدا و به یاری او. چشم بد از میان گوشتش، پوستش، استخوانش، عصبش و رگ‌هایش خارج شد و با جبرئیل و میکائیل (علیها السلام) برخورد کرد. گفتند: «ای چشم کجا می‌روی»! گفت: «به‌سوی شتر می‌روم و آن را از ردیف شتران دور می‌کنم و حیوان را از افسارش و الاغ را از سرزمینش و بچّه را از آغوش مادرش [دور می‌کنم] و مرد جوان نیرومند را از پاهایش بر زمین می‌افکنم». جبرئیل و میکائیل به آن گفتند: «ای چشم! به صحرا برو. آنجا ماری است که دو چشم دارد، چشمی از آب و چشمی از آتش». و این‌گونه خداوند بر چشم بد، رو ترش‌کردن بازدارنده، سنگ خشک، روح چشم‌زخم زننده و آتشِ جوینده‌ی آتش مهر می‌نهد. به یاری خدا چشم بد را به اهلش و در دو طرفش، دو پهلویش و به محبوب‌ترین دوستانش برگرداندم و [همچنین] به اراده‌ی خداوند و [به کمک] سخن او آیا کافران ندیدند که آسمان‌ها و زمین به هم پیوسته بودند، و ما آن‌ها را از یکدیگر باز کردیم و هرچیز زنده‌ای را از آب قرار دادیم؟! آیا ایمان نمی‌آورند؟!. (

انبیاء/۳۰

) فَارْجِعِ الْبَصَرَ هَلْ تَری مِنْ فُطُورٍ ثُمَّ ارْجِعِ الْبَصَرَ کَرَّتَیْنِ یَنْقَلِبْ إِلَیْکَ الْبَصَرُ خاسِئاً وَ هُوَ حَسِیرٌ.

ای پسر مسعود: گروهی پس از من می‌آیند که غذاهای رنگین و گوارا می‌خورند، چهار پایان را سوار می‌شوند، مانند زنان که برای شوهر خویش آرایش می‌کنند، آرایش می‌کنند. و آرایش خود را مانند زنان به دیگران نشان دهند؛ لباسشان لباس پادشاهان ستمگر می‌باشد. ... ای پسر مسعود! دانشمند و فقیهان آن زمان نادرست و دروغگویند. آگاه باش که اینان بدان خلق خدایند. و مانند آنان است کسانی که پیروان ایشانند و کسانی که پیش آنان می‌روند و از آنان می‌گیرند و دوست دارند ایشان را و همنشینی با آنان می‌کنند و با آن‌ها بدان آفریدگان خدا مشورت می‌کنند وارد می‌کنند ایشان را در آتش جهنّم: آن‌ها کران، گنگ‌ها و کورانند لذا [از راه خطا] بازنمی‌گردند!. (

بقره/۱۸

) و روز قیامت، آن‌ها را بر صورت‌هایشان محشور می‌کنیم، درحالی‌که نابینا و گنگ و کرند جایگاهشان دوزخ است هر زمان آتش آن فرونشیند، شعله تازه‌ای بر آنان می‌افزاییم!. (

اسراء/۹۷

)». هرگاه پوست‌های تنشان [در آن] بریان گردد [و بسوزد]، پوس-ت‌های دیگری به‌جای آن قرار می‌دهیم، تا کیفر [الهی] را بچشند. (

نساء/۵۶

)». نزدیک است [دوزخ] از شدّت غضب پاره‌پاره شود. (

ملک/۷

) هرگاه بخواهند از غم و اندوه‌های دوزخ خارج شوند، آن‌ها را به آن بازمی‌گردانند و [به آنان گفته می‌شود]: بچشید عذاب سوزان را!. (

حج/۲۲

) برای آنان در آن [دوزخ] ناله‌های دردناکی است و چیزی نمی‌شنوند. (

انبیاء/۱۰۰

) آنان ادّعا می‌کنند که بر دین و سنّت، راه و روش منند آنان از من بدور و من از آنان بیزارم. ای پسر مسعود با آنان در اجتماع هم‌نشینی ننمایید در بازار با ایشان خرید و فروش مکنید، راه را نشانشان ندهید، آبشان ندهید.

ای پسر مسعود! زمانی بر مردم بیاید که صبرکننده‌ی بر دینش مانند کسی است که آتش در دست خود بگیرد. اگر گرگ بودی در این زمان که بسیار خوب وگرنه مرا گرگ صفتان می‌خورند. ای پسر مسعود! دانشمند و فقیهان آن زمان نادرست و دروغگویند. آگاه باش که اینان بدترین خلق خدا هستند و مانند آنان است کسانی که پیروان ایشانند و کسانی که پیش آنان می‌روند و از آنان می‌گیرند و ایشان را دوست دارند و همنشینی با آنان می‌کنند و با آن‌ها بدترین آفریدگان خدا مشورت می‌کنند. ایشان را در آتش جهنّم وارد می‌کنند. آن‌ها کران، گنگ‌ها و کورانند لذا [از راه خطا] بازنمی‌گردند!. (

بقره/۱۸

) و روز قیامت، آن‌ها را بر صورت‌هایشان محشور می‌کنیم، درحالی‌که نابینا و گنگ و کرند جایگاهشان دوزخ است هر زمان آتش آن فرونشیند، شعله تازه‌ای بر آنان می‌افزاییم!. (

اسراء/۹۷

) هرگاه پوست‌های تنشان [در آن] بریان گردد [و بسوزد]، پوست‌های دیگری به‌جای آن قرار می‌دهیم، تا کیفر [الهی] را بچشند. (

نساء/۵۶

)». و إِذا أُلْقُوا فِیها سَمِعُوا لَها شَهِیقاً وَ هِیَ تَفُورُ. تَکادُ تَمَیَّزُ مِنَ الْغَیْظِ. هرگاه بخواهند از غم و اندوه‌های دوزخ خارج شوند، آن‌ها را به آن بازمی‌گردانند و [به آنان گفته می‌شود]: بچشید عذاب سوزان را!. (

حج/۲۲

) آنان در آن [دوزخ] ناله‌های دردناکی است و چیزی نمی‌شنوند. (

انبیاء/۱۰۰

) آنان ادّعا می‌کنند که بر دین و سنّت، در راه و روش من هستند آنان از من به دور و من از آنان بیزارم. ای پسر مسعود! با آنان در اجتماع هم‌نشینی ننمایید در بازار با ایشان خرید و فروش نکنید، راه را نشانشان ندهید، آبشان ندهید.

هرکس دندان آسیابش درد کرد، انگشتش را بر روی آن بگذارد و این دو آیه را هفت مرتبه بخواند: او کسی است که شما را از یک نفس آفرید! و شما دو گروه هستید: بعضی پایدار [از نظر ایمان یا خلقت کامل]، و بعضی ناپایدار ما آیات خود را برای کسانی که می‌فهمند، تشریح نمودیم!. (

انعام/۹۸

) و [آیه‌ی] هُوَ الَّذِی أَنْشَأَکُمْ وَ جَعَلَ لَکُمُ السَّمْعَ وَ الْأَبْصارَ وَ الْأَفْئِدَةَ قَلیلاً ما تَشْکُرُونَ که به اذن خدا بهبودی می‌یابد.

از امام حسین (علیه السلام) روایت شده که فرمود: «ما دوازده مهدی داریم. اوّل آن‌ها امیرالمؤمنین علیّ‌بن‌ابی‌طالب (علیه السلام) و آخر آن‌ها نهمین فرزند من است، او امامی است که قیام به حق می‌نماید؛ خداوند زمین را بعد از مردنش به‌وسیله‌ی او زنده می‌کند. (

روم/۲۴

) هم به‌وسیله‌ی او دین حق (اسلام) را زنده می‌کند. و بر همه‌ی ادیان غالب سازد، هرچند مشرکان کراهت داشته باشند!. (

صف/۹

) او غیبتی دارد که در آن مردم بسیاری از دین برمی‌گردند. و گروهی دیگر بر دین حق (اسلام) ثابت باشند. برخی [از روی سرزنش] به آن‌ها می‌گویند: مَتی هذَا الْوَعْدُ إِنْ کُنْتُمْ صادِقِینَ امّا آگاه باشید آن‌ها که در غیبت وی با تحمّل رنج‌ها و تکذیب بی‌دینان بر عقیده‌ی خود ثابت می‌مانند، مثل کسانی هستند که با شمشیر در رکاب رسول خدا (صلی الله علیه و آله) جهاد کردند»!
